// Get text from the Telegram message
const rawText = $input.first().json.message.text; 
const results = [];

// 1. Identify the Date (DD/MM/YY)
const dateMatch = rawText.match(/(\d{2}\/\d{2}\/\d{2})/);
const date = dateMatch ? dateMatch[1] : "Unknown Date";

// 2. Helper to extract numbers following specific keywords
const getVal = (keyword, textSegment) => {
    if (!textSegment) return 0;
    // Handles dots, spaces, and newlines between label and number
    const regex = new RegExp(keyword + "[\\.\\s\\n]+(\\d+)", "i");
    const match = textSegment.match(regex);
    return match ? parseInt(match[1], 10) : 0;
};

// 3. Define Sections
const roomPart = rawText.split(/Restaurant sale/i)[0];
const restPart = rawText.split(/Restaurant sale/i)[1]?.split(/Today's cash expenses/i)[0] || "";
const expensePart = rawText.split(/Today's cash expenses/i)[1]?.split(/Opening balance/i)[0] || "";
const balancePart = rawText.split(/Opening balance/i)[1] || "";

// --- 4. CREATE SUMMARY ITEM ---
results.push({
    json: {
        dataType: "summary",
        Date: date,
        Rooms_Sold: getVal("sold", roomPart),
        Total_Room_Revenue: getVal("Total revenue", roomPart),
        Room_Cash: getVal("Cash", roomPart),
        Room_Card: getVal("Card", roomPart),
        Room_UPI: getVal("Upi", roomPart),
        Room_Online: getVal("Online", roomPart),
        Restaurant_Sale: getVal("Restaurant sale", rawText),
        Restaurant_Cash: getVal("Cash", restPart),
        Restaurant_Card: getVal("Card", restPart),
        Restaurant_UPI: getVal("Upi", restPart),
        Restaurant_Swiggy: getVal("Swiggy", restPart),
        Restaurant_Zomato: getVal("Zomato", restPart),
        Room_Posting: getVal("Room posting", restPart),
        Opening_Balance: getVal("Opening balance", rawText),
        Closing_Balance: getVal("Closing balance", rawText)
    }
});

// --- 5. CREATE INDIVIDUAL EXPENSE ITEMS ---
const expenseLines = expensePart.split('\n');
for (let line of expenseLines) {
    line = line.trim();
    // Skip empty lines, the total line, or lines without dots
    if (!line || line.toLowerCase().includes("total") || !line.includes('..')) continue;

    const match = line.match(/^(.+?)\.+\s*(\d+)$/);
    if (match) {
        results.push({
            json: {
                dataType: "expense",
                Date: date,
                Expense_Item: match[1].trim(),
                Amount: parseInt(match[2], 10)
            }
        });
    }
}

return results;
